diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..d5c4a9d96bbf 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -22,6 +22,7 @@
 #include "llvm/IR/PatternMatch.h"
 #include "llvm/Transforms/InstCombine/InstCombiner.h"
 #include "llvm/Transforms/Utils/Local.h"
+#include "llvm/Support/raw_ostream.h"

 using namespace llvm;
 using namespace PatternMatch;
@@ -1366,6 +1367,21 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
     }
   }
+  // Also strip AND with negated power of two for equality comparisons.
+  if (!MatchedAnd1 && Pred1 == ICmpInst::ICMP_EQ) {
+    Value *X;
+    if (match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask1))))) {
+      MatchedAnd1 = true;
+      V1 = X;
+    }
+  }
+  if (!MatchedAnd2 && Pred2 == ICmpInst::ICMP_EQ) {
+    Value *X;
+    if (match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask2))))) {
+      MatchedAnd2 = true;
+      V2 = X;
+    }
+  }

   if (V1 != V2)
     return nullptr;
@@ -1385,7 +1401,17 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                 IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);
-
+  // If one comparison's true range is a subset of the other's, we can simplify.
+  ConstantRange TrueRange1 = (IsAnd && !MatchedAnd1) ? CR1.inverse() : CR1;
+  ConstantRange TrueRange2 = (IsAnd && !MatchedAnd2) ? CR2.inverse() : CR2;
+  if (TrueRange1.contains(TrueRange2)) {
+    // TrueRange2 is subset of TrueRange1.
+    // For AND, result = subset (ICmp2); for OR, result = superset (ICmp1).
+    return IsAnd ? ICmp2 : ICmp1;
+  }
+  if (TrueRange2.contains(TrueRange1)) {
+    return IsAnd ? ICmp1 : ICmp2;
+  }
   Type *Ty = V1->getType();
   Value *NewV = V1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
@@ -3578,7 +3604,102 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
        (RHSC->isZero() && *LHSC == *MaskC)))
     return Builder.createIsFPClass(X, IsAnd ? FPClassTest::fcNormal
                                             : ~FPClassTest::fcNormal);
-
+  // (icmp ult X, C) & (icmp eq (and X, Mask), K) -> icmp eq (and X, Mask), K
+  // when (K + (1 << trailing zeros of ~Mask) - 1) < C.
+  // Similarly for swapped operands.
+  if (IsAnd && LHSC && RHSC) {
+    Value *X1, *X2;
+    const APInt *Mask;
+    // Check for ult on one side and eq with and on the other.
+    if (PredL == ICmpInst::ICMP_ULT && PredR == ICmpInst::ICMP_EQ &&
+        match(LHS0, m_Value(X1)) &&
+        match(RHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      // Mask is negative power of two, i.e., clears low k bits.
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *RHSC + (APInt::getOneBitSet(RHSC->getBitWidth(), k) - 1);
+      if (Max.ult(*LHSC))
+        return RHS;
+    }
+    // Check for ule on one side and eq with and on the other.
+    if (PredL == ICmpInst::ICMP_ULE && PredR == ICmpInst::ICMP_EQ &&
+        match(LHS0, m_Value(X1)) &&
+        match(RHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *RHSC + (APInt::getOneBitSet(RHSC->getBitWidth(), k) - 1);
+      if (Max.ule(*LHSC))
+        return RHS;
+    }
+    // Check for slt on one side and eq with and on the other.
+    if (PredL == ICmpInst::ICMP_SLT && PredR == ICmpInst::ICMP_EQ &&
+        match(LHS0, m_Value(X1)) &&
+        match(RHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *RHSC + (APInt::getOneBitSet(RHSC->getBitWidth(), k) - 1);
+      if (Max.slt(*LHSC))
+        return RHS;
+    }
+    // Check for sle on one side and eq with and on the other.
+    if (PredL == ICmpInst::ICMP_SLE && PredR == ICmpInst::ICMP_EQ &&
+        match(LHS0, m_Value(X1)) &&
+        match(RHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *RHSC + (APInt::getOneBitSet(RHSC->getBitWidth(), k) - 1);
+      if (Max.sle(*LHSC))
+        return RHS;
+    }
+    // Swapped.
+    if (PredR == ICmpInst::ICMP_ULT && PredL == ICmpInst::ICMP_EQ &&
+        match(RHS0, m_Value(X1)) &&
+        match(LHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *LHSC + (APInt::getOneBitSet(LHSC->getBitWidth(), k) - 1);
+      if (Max.ult(*RHSC))
+        return LHS;
+    }
+    // Swapped ule.
+    if (PredR == ICmpInst::ICMP_ULE && PredL == ICmpInst::ICMP_EQ &&
+        match(RHS0, m_Value(X1)) &&
+        match(LHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *LHSC + (APInt::getOneBitSet(LHSC->getBitWidth(), k) - 1);
+      if (Max.ule(*RHSC))
+        return LHS;
+    }
+    // Swapped slt.
+    if (PredR == ICmpInst::ICMP_SLT && PredL == ICmpInst::ICMP_EQ &&
+        match(RHS0, m_Value(X1)) &&
+        match(LHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *LHSC + (APInt::getOneBitSet(LHSC->getBitWidth(), k) - 1);
+      if (Max.slt(*RHSC))
+        return LHS;
+    }
+    // Swapped sle.
+    if (PredR == ICmpInst::ICMP_SLE && PredL == ICmpInst::ICMP_EQ &&
+        match(RHS0, m_Value(X1)) &&
+        match(LHS0, m_And(m_Value(X2), m_NegatedPower2(Mask))) &&
+        X1 == X2) {
+      APInt NegMask = -(*Mask);
+      unsigned k = NegMask.exactLogBase2();
+      APInt Max = *LHSC + (APInt::getOneBitSet(LHSC->getBitWidth(), k) - 1);
+      if (Max.sle(*RHSC))
+        return LHS;
+    }
+  }
   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }

