; ModuleID = '<stdin>'
source_filename = "<stdin>"

define i1 @merge_range_check_and(i8 %a) {
  %and = icmp ult i8 %a, 2
  ret i1 %and
}

filecheck.tgt:
; ModuleID = '<stdin>'
source_filename = "<stdin>"

define i1 @merge_range_check_and(i8 %a) {
  %and = icmp ult i8 %a, 2
  ret i1 %and
}

log.expect_optimized_program:
define i1 @merge_range_check_and(i8 %a) {
  %and = icmp eq i8 %a, 2
  ret i1 %and
}

log.current_optimized_program:
define i1 @merge_range_check_and(i8 %a) {
  %and = icmp ult i8 %a, 2
  ret i1 %and
}

log.expect_optimized_program:
define i1 @implied_select_icmp_eq_and_pow2(i32 %x) {
  %1 = and i32 %x, -32
  %2 = icmp eq i32 %1, 128
  ret i1 %2
}

log.current_optimized_program:
define i1 @implied_select_icmp_eq_and_pow2(i32 %x) {
  %and = and i32 %x, -32
  %icmp2 = icmp eq i32 %and, 128
  ret i1 %icmp2
}

log.expect_optimized_program:
define i1 @implied_range_check(i8 %a) {
  %1 = and i8 %a, -2
  %and = icmp eq i8 %1, 2
  ret i1 %and
}

log.current_optimized_program:
define i1 @implied_range_check(i8 %a) {
  %masked = and i8 %a, -2
  %cmp2 = icmp eq i8 %masked, 2
  ret i1 %cmp2
}

